{
  "command": "duckdb '/Users/shreyashankar/Documents/projects/DataAgentBench/query_yelp/query_dataset/yelp_user.db' \"SELECT business_ref, AVG(rating) AS avg_rating, COUNT(*) AS n FROM review WHERE date >= '2016-01-01' AND date < '2016-07-01' GROUP BY business_ref HAVING COUNT(*) >= 5 ORDER BY avg_rating DESC, n DESC LIMIT 20;\"",
  "description": "Query top avg-rated businesses in H1 2016"
}

{
  "command": "duckdb '/Users/shreyashankar/Documents/projects/DataAgentBench/query_yelp/query_dataset/yelp_user.db' \"SELECT MIN(date), MAX(date) FROM review;\"",
  "description": "Get date range of reviews"
}

{
  "command": "duckdb '/Users/shreyashankar/Documents/projects/DataAgentBench/query_yelp/query_dataset/yelp_user.db' \"SELECT date FROM review LIMIT 20;\"",
  "description": "Sample review dates"
}

{
  "command": "duckdb '/Users/shreyashankar/Documents/projects/DataAgentBench/query_yelp/query_dataset/yelp_user.db' "
WITH parsed AS (
  SELECT business_ref, rating,
    COALESCE(
      try_strptime(date, '%Y-%m-%d %H:%M:%S'),
      try_strptime(date, '%B %d, %Y at %I:%M %p'),
      try_strptime(date, '%d %b %Y, %H:%M')
    ) AS dt
  FROM review
)
SELECT COUNT(*) total, COUNT(dt) parsed FROM parsed;
"",
  "description": "Verify date parsing coverage"
}

